UPDATE ai_client_system_prompt
prompt_id = #{promptId}, prompt_name = #{promptName}, prompt_content = #{promptContent}, description = #{description}, status = #{status}, update_time = #{updateTime},
WHERE id = #{id}

mapper.select:
SELECT id, prompt_id, prompt_name, prompt_content, description, status, create_time, update_time
FROM ai_client_system_prompt
WHERE id = #{id}

SELECT id, prompt_id, prompt_name, prompt_content, description, status, create_time, update_time
FROM ai_client_system_prompt
WHERE prompt_id = #{promptId}

SELECT id, prompt_id, prompt_name, prompt_content, description, status, create_time, update_time
FROM ai_client_system_prompt

    AND prompt_id = #{promptId}
    AND prompt_name LIKE CONCAT('%', #{promptName}, '%')
    AND status = #{status}

ORDER BY create_time DESC
